//! spectral-atlas — measures per-layer activation spectrum and fits a
//! power-law `σ_k ∝ 1/k^α` to the singular value distribution.
//! The result is the Spectral Atlas: per-layer `α(l)` that grounds
//! `GnosticValley.lean`'s conjectural noise-color classification.
//!
//! NOTE on basis choice (corrected 2026-05-03 after a falsified v1):
//! Hidden dims are an UNORDERED basis — any permutation of dim indices
//! produces the same model. So a *spatial-frequency* PSD across dim
//! indices is meaningless (a v1 of this binary measured it; every layer
//! came back α ≈ 0 / r² ≈ 0, exactly because the signal had no spatial
//! structure to fit). The correct ordered signal is the singular value
//! spectrum of the activation matrix over a sample of tokens — when
//! sorted descending by σ, the rate of decay encodes how concentrated
//! the variance is in few principal components.
//!
//! For each layer L:
//!   1. Hook into forward_one's capture mode to collect residual
//!      activations across N tokens, building an N × d matrix
//!   2. Compute the top-k singular values via power iteration
//!      (reusing top_k_singular_values from standing_wave_pinning)
//!   3. Fit a power law in log-log space: log σ_k = log σ_1 − α · log k
//!      via simple linear least-squares
//!   4. Classify into NoiseColor (white if α < 0.5, pink if 0.5..1.5,
//!      brown if α ≥ 1.5)
//!
//! Output: JSONL, one row per layer:
//!   {"layer": 10, "alpha": 1.94, "fit_r2": 0.95, "color": "brown",
//!    "psd_first_5": [...], "tokens_used": 16}
//!
//! Usage:
//!   spectral-atlas --knot model.knot --tokens 1,...,N --out model.psd.jsonl
//!
//! Verifies (or falsifies) the GnosticValley conjecture: that mid-pipeline
//! layers (8-17 on Qwen2.5-0.5B) are brown-spectrum (α ≥ 1.5) and edge
//! layers (0-2) are white-spectrum (α < 0.5).

use std::env;
use std::fs::OpenOptions;
use std::io::Write;

use distributed_inference::loader::KnotWeights;
use distributed_inference::standing_wave_pinning::top_k_singular_values;
use distributed_inference::NativeLlamaPipeline;

struct Args {
    knot_path: String,
    tokens: Vec<u32>,
    out_path: String,
}

fn parse_args() -> Result<Args, String> {
    let argv: Vec<String> = env::args().collect();
    let mut knot_path: Option<String> = None;
    let mut tokens: Option<Vec<u32>> = None;
    let mut out_path: Option<String> = None;
    let mut i = 1;
    while i < argv.len() {
        match argv[i].as_str() {
            "--knot" => {
                i += 1;
                knot_path = Some(argv.get(i).ok_or("--knot")?.clone());
            }
            "--tokens" => {
                i += 1;
                let raw = argv.get(i).ok_or("--tokens")?;
                tokens = Some(
                    raw.split(',')
                        .map(|s| s.trim().parse().map_err(|e| format!("bad token: {}", e)))
                        .collect::<Result<_, _>>()?,
                );
            }
            "--token-range" => {
                i += 1;
                let raw = argv.get(i).ok_or("--token-range")?;
                let (a, b) = raw
                    .split_once("..")
                    .ok_or("--token-range expects START..END")?;
                let s: u32 = a.parse().map_err(|e| format!("bad start: {}", e))?;
                let e: u32 = b.parse().map_err(|e| format!("bad end: {}", e))?;
                tokens = Some((s..e).collect());
            }
            "--out" => {
                i += 1;
                out_path = Some(argv.get(i).ok_or("--out")?.clone());
            }
            other => return Err(format!("unknown arg: {}", other)),
        }
        i += 1;
    }
    Ok(Args {
        knot_path: knot_path.ok_or("--knot required")?,
        tokens: tokens.ok_or("--tokens or --token-range required")?,
        out_path: out_path.ok_or("--out required")?,
    })
}

/// Build the centered N×d activation matrix from captured samples,
/// flattened row-major.
fn center_activations(samples: &[Vec<f32>]) -> (Vec<f32>, usize, usize) {
    let n = samples.len();
    if n == 0 {
        return (Vec::new(), 0, 0);
    }
    let d = samples[0].len();
    let mut mean = vec![0.0f32; d];
    for s in samples {
        for j in 0..d {
            mean[j] += s[j];
        }
    }
    for j in 0..d {
        mean[j] /= n as f32;
    }
    let mut x = vec![0.0f32; n * d];
    for (i, s) in samples.iter().enumerate() {
        for j in 0..d {
            x[i * d + j] = s[j] - mean[j];
        }
    }
    (x, n, d)
}

/// Fit log P(f) = log A − α · log f by simple linear least-squares.
/// Skips the DC bin (k=0) and frequencies where psd is non-positive.
/// Returns (alpha, r_squared).
fn fit_power_law(psd: &[f32]) -> (f32, f32) {
    // Build (log f, log P(f)) pairs
    let mut pts: Vec<(f32, f32)> = Vec::with_capacity(psd.len());
    for k in 1..psd.len() {
        if psd[k] > 0.0 {
            pts.push(((k as f32).ln(), psd[k].ln()));
        }
    }
    if pts.len() < 3 {
        return (0.0, 0.0);
    }
    let n = pts.len() as f32;
    let sum_x: f32 = pts.iter().map(|p| p.0).sum();
    let sum_y: f32 = pts.iter().map(|p| p.1).sum();
    let mean_x = sum_x / n;
    let mean_y = sum_y / n;
    let mut s_xy = 0.0f32;
    let mut s_xx = 0.0f32;
    let mut s_yy = 0.0f32;
    for &(x, y) in &pts {
        let dx = x - mean_x;
        let dy = y - mean_y;
        s_xy += dx * dy;
        s_xx += dx * dx;
        s_yy += dy * dy;
    }
    if s_xx == 0.0 {
        return (0.0, 0.0);
    }
    let slope = s_xy / s_xx; // log P = log A + slope · log f
    let alpha = -slope; // S(f) ∝ 1/f^α  →  log P = log A − α log f
    let r2 = if s_yy == 0.0 {
        0.0
    } else {
        (s_xy * s_xy) / (s_xx * s_yy)
    };
    (alpha, r2)
}

fn classify_color(alpha: f32) -> &'static str {
    if alpha >= 1.5 {
        "brown"
    } else if alpha >= 0.5 {
        "pink"
    } else if alpha >= -0.5 {
        "white"
    } else if alpha >= -1.5 {
        "blue"
    } else {
        "violet"
    }
}

fn main() -> Result<(), String> {
    let args = parse_args().inspect_err(|_| {
        eprintln!("usage: spectral-atlas --knot PATH --token-range START..END --out PATH");
    })?;
    eprintln!(
        "[atlas] knot={} tokens={} out={}",
        args.knot_path,
        args.tokens.len(),
        args.out_path
    );

    // Build pipeline; turn on simulate_routing + capture so per-layer
    // residuals get pushed to standing_wave_captured. This is the same
    // calibration mode standing-wave-pca uses.
    let knot = KnotWeights::load(&args.knot_path).map_err(|e| format!("knot load: {:?}", e))?;
    let mut pipeline = NativeLlamaPipeline::from_knot(knot, false, 0.8);
    let num_layers = pipeline.num_layers();
    let hidden_dim = pipeline.hidden_dim();
    eprintln!(
        "[atlas] num_layers={} hidden_dim={}",
        num_layers, hidden_dim
    );

    // Capture every boundary
    let all_layers: Vec<usize> = (0..num_layers.saturating_sub(1)).collect();
    pipeline.set_standing_wave_simulate_routing(true);
    pipeline.set_standing_wave_inject_at_layers(Some(all_layers.clone()));
    pipeline.set_standing_wave_capture(true);

    let t0 = std::time::Instant::now();
    for (step, &token) in args.tokens.iter().enumerate() {
        pipeline
            .forward_one(token as usize, step, false)
            .map_err(|e| format!("forward_one(step={}): {}", step, e))?;
    }
    eprintln!(
        "[atlas] capture: {} tokens × {} layers in {} ms",
        args.tokens.len(),
        num_layers,
        t0.elapsed().as_millis()
    );

    // Open output sink
    let mut sink = OpenOptions::new()
        .create(true)
        .truncate(true)
        .write(true)
        .open(&args.out_path)
        .map_err(|e| format!("open {}: {}", args.out_path, e))?;
    writeln!(
        sink,
        "# spectral-atlas: per-layer power-law fit S(f) ∝ 1/f^α"
    )
    .map_err(|e| format!("write: {}", e))?;
    writeln!(
        sink,
        "# columns: layer alpha fit_r2 color tokens_used psd_first_3 psd_last_3"
    )
    .map_err(|e| format!("write: {}", e))?;

    println!("# layer alpha fit_r2 color tokens_used sigma_1 sigma_k");
    // Number of singular values to compute per layer. Bounded by min(n, d).
    let k_top = hidden_dim.min(args.tokens.len()).min(64);
    for l in 0..num_layers {
        let samples = pipeline.standing_wave_captured_get(l);
        let n = samples.len();
        if n == 0 {
            // Last boundary doesn't fire (no l+1); skip silently.
            continue;
        }
        // Build centered N × d activation matrix
        let (x, rows, cols) = center_activations(samples);
        if rows < 3 || cols == 0 {
            eprintln!("[atlas] layer {}: not enough samples ({}) for SVD", l, rows);
            continue;
        }
        let k_eff = k_top.min(rows).min(cols);
        let sigmas = top_k_singular_values(&x, rows, cols, k_eff, 25, 0xA71A5);
        let (alpha, r2) = fit_power_law(&sigmas);
        let color = classify_color(alpha);
        let sigma_1 = sigmas.first().copied().unwrap_or(0.0);
        let sigma_k = sigmas.last().copied().unwrap_or(0.0);
        let sigmas_str: Vec<String> = sigmas.iter().take(8).map(|v| format!("{:.3}", v)).collect();
        writeln!(
            sink,
            "{} {:.4} {:.4} {} {} {:.3} {:.3} [{}]",
            l,
            alpha,
            r2,
            color,
            n,
            sigma_1,
            sigma_k,
            sigmas_str.join(","),
        )
        .map_err(|e| format!("write: {}", e))?;
        println!(
            "{} {:.4} {:.4} {} {} {:.3} {:.3}",
            l, alpha, r2, color, n, sigma_1, sigma_k
        );
    }

    eprintln!("[atlas] DONE: per-layer atlas written to {}", args.out_path);
    Ok(())
}
